-- ============================================================
-- JOBS
-- ============================================================
CREATE TABLE IF NOT EXISTS jobs (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id   UUID REFERENCES proposals(id) ON DELETE RESTRICT UNIQUE,
  job_number    TEXT UNIQUE NOT NULL,
  status        TEXT DEFAULT 'scheduled' CHECK (status IN (
                  'scheduled','in_progress','completed','closed','cancelled'
                )),
  move_date     DATE NOT NULL,
  move_time     TIME,  -- optional start time on move_date
  move_end_date DATE,  -- end date for multi-day moves; NULL = same day as move_date
  move_end_time TIME,  -- optional end time; NULL → downstream defaults to move_time + 8h, or 18:00
  revenue       BIGINT NOT NULL,
  gcal_event_id TEXT,
  notes         TEXT,
  created_by    UUID REFERENCES auth.users(id),
  created_at    TIMESTAMPTZ DEFAULT now()
);

