  id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name                TEXT NOT NULL,
  phone               TEXT,
  skills              TEXT[] DEFAULT '{}',
  daily_rate          BIGINT,
  availability_status TEXT DEFAULT 'available',
  emergency_contact   TEXT,
  notes               TEXT,
  is_active           BOOLEAN DEFAULT true,
