);

-- ============================================================
-- JOB ASSIGNMENTS (explicit FK per type)
-- ============================================================
CREATE TABLE IF NOT EXISTS job_assignments (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id          UUID REFERENCES jobs(id) ON DELETE CASCADE,
  assignment_type TEXT NOT NULL CHECK (assignment_type IN ('fleet', 'crew')),
  fleet_id       UUID REFERENCES fleet(id) ON DELETE SET NULL,
  crew_id         UUID REFERENCES crew(id) ON DELETE SET NULL,
  role            TEXT,
  daily_rate      BIGINT,
  days            INTEGER DEFAULT 1,
  created_at      TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- EXPENSES
-- ============================================================
CREATE TABLE IF NOT EXISTS expenses (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id       UUID REFERENCES jobs(id) ON DELETE RESTRICT,
  amount       BIGINT NOT NULL CHECK (amount > 0),
  category     TEXT NOT NULL,
  description  TEXT,
  receipt_url  TEXT,
  incurred_at  DATE NOT NULL DEFAULT CURRENT_DATE,
  logged_by    UUID REFERENCES auth.users(id),
  created_at   TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- INVOICES
-- ============================================================
CREATE TABLE IF NOT EXISTS invoices (
  id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id         UUID REFERENCES jobs(id) ON DELETE RESTRICT UNIQUE,
  invoice_number TEXT UNIQUE NOT NULL,
  total_amount   BIGINT NOT NULL,
  paid_amount    BIGINT NOT NULL DEFAULT 0,
  status         TEXT DEFAULT 'draft' CHECK (status IN (
                   'draft','sent','partially_paid','paid','overdue','cancelled'
                 )),
  due_date       DATE,
  notes          TEXT,
  pdf_url        TEXT,
  created_at     TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- PAYMENTS (from customer, linked to the job)
-- ============================================================
-- Payments live at the job level so a down payment can be taken on a
-- scheduled (not yet invoiced) job. The invoice's paid_amount/status is kept
-- in sync by the update_invoice_status trigger, matched by job_id.
CREATE TABLE IF NOT EXISTS payments (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id       UUID NOT NULL REFERENCES jobs(id) ON DELETE RESTRICT,
  amount       BIGINT NOT NULL CHECK (amount > 0),
  payment_type TEXT NOT NULL CHECK (payment_type IN (
                 'down_payment','partial','final','refund'
               )),
  method       TEXT CHECK (method IN ('cash','transfer','qris')),
  paid_at      DATE NOT NULL DEFAULT CURRENT_DATE,
  notes        TEXT,
  created_at   TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- JOB TIMELINE
-- ============================================================
CREATE TABLE IF NOT EXISTS job_timeline (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id       UUID REFERENCES jobs(id) ON DELETE CASCADE,
  occurred_at  TIMESTAMPTZ DEFAULT now(),
  event_type   TEXT NOT NULL,
  notes        TEXT,
  logged_by    UUID REFERENCES auth.users(id)
);

-- ============================================================
-- SYSTEM SETTINGS
-- ============================================================
CREATE TABLE IF NOT EXISTS system_settings (
  key         TEXT PRIMARY KEY,
  value       TEXT NOT NULL,
  category    TEXT,
  description TEXT,
  updated_at  TIMESTAMPTZ DEFAULT now(),
  updated_by  UUID REFERENCES auth.users(id)
);

